// The outline of Czechia and its three historical lands as SVG paths,
// projected equirectangularly (cos-corrected at the mid-latitude). The
// national outline dissolves geoBoundaries.org gbOpen kraje (ADM1; sourced
// from the Czech Office for Surveying, CC BY 4.0). The land borders are the
// REAL historical ones: Moravia's boundary — including the Moravian
// enclaves inside Silesia — comes from the cadastral-level reconstruction
// published as KML at hranice.moravy.eu (Moravská národní obec + Společnost
// pro Moravu a Slezsko, 2017–2025; no explicit license, used with
// attribution), clipped to the current state border; Bohemia and Silesia
// are the west/northeast remainders, so every seam is watertight by
// construction. Regenerated by the regiongen script (gen4.ts) in the
// session scratchpad.

// The three historical lands — a closed union, so everything keyed by land
// (clubLand, LAND_BORDER_WIPES) fails the type check on a rename instead of
// silently losing its entry.
export type Land = 'Bohemia' | 'Moravia' | 'Silesia';

export interface CzechRegion {
  readonly name: Land;
  readonly d: string;
  // Label anchor, in viewBox units.
  readonly cx: number;
  readonly cy: number;
  // Label font size in viewBox units — sized so the word stays inside its
  // own land (Silesia is a narrow wedge and needs a much smaller type).
  readonly labelSize: number;
  // Rotation in degrees around the anchor — lets a label run along its
  // land's axis (Silesia's wedge points northeast).
  readonly labelAngle: number;
}

